function fmtDate(s) {
  const [y, m, d] = s.split("-").map(Number)
  return new Date(y, m - 1, d).toLocaleDateString("en-US", {
    year: "numeric", month: "long", day: "numeric"
  })
}

allDates = [...new Set(daily_occ.map(r =&gt; r.date))].sort().reverse()
latestDate = allDates[0]
cityValidation = FileAttachment("data/city_validation.json").json().catch(() =&gt; null)





























