latestRows = daily_occ.filter(r =&gt; r.date === latestDate)

function getVal(rows, key) {
  const row = rows.find(r =&gt; r.key === key)
  return row ? row.ind : null
}

validationChecks = {
  const rows = latestRows
  const checks = []

  // Check 1: all expected keys present
  const expectedKeys = [
    "all_shelter","room_based","singles_sector","singles_shelter","allied_summ",
    "temp_summ","iso_summ","fam_total","fam_emerg","fam_trans_r","fam_hotel",
    "sng_hotel","singles_total","emerg_total","mix_emerg","men_emerg","wom_emerg",
    "yth_emerg","trans_total","mix_trans","fam_trans_b","men_trans","wom_trans",
    "yth_trans","allied_total","respites","dropin","temp_resp","hotels","iso"
  ]
  const presentKeys = new Set(rows.map(r =&gt; r.key))
  const missingKeys = expectedKeys.filter(k =&gt; !presentKeys.has(k))
  checks.push({
    name: "All expected rows present",
    pass: missingKeys.length === 0,
    detail: missingKeys.length &gt; 0 ? `Missing: ${missingKeys.join(", ")}` : null
  })

  // Check 2: All Shelter Programs total = sum of components
  const allShelter = getVal(rows, "all_shelter")
  const compSum = ["fam_total","sng_hotel","singles_total","allied_total","temp_resp","hotels","iso"]
    .reduce((s, k) =&gt; s + (getVal(rows, k) ?? 0), 0)
  checks.push({
    name: "All Shelter Programs rollup matches components",
    pass: allShelter === compSum,
    detail: allShelter !== compSum
      ? `all_shelter.ind=${allShelter}, component sum=${compSum}, diff=${allShelter - compSum}`
      : null
  })

  // Check 3: Singles sectors total = emergency + transitional
  const singlesTotal = getVal(rows, "singles_total")
  const emergTotal = getVal(rows, "emerg_total")
  const transTotal = getVal(rows, "trans_total")
  checks.push({
    name: "Singles sectors rollup: emergency + transitional = singles total",
    pass: singlesTotal === (emergTotal + transTotal),
    detail: singlesTotal !== (emergTotal + transTotal)
      ? `singles=${singlesTotal}, emerg+trans=${emergTotal + transTotal}`
      : null
  })

  // Check 4: For every row with non-null cap, occ + unocc = cap (within 1, for rounding)
  const capRows = rows.filter(r =&gt; r.cap !== null && r.cap &gt; 0)
  const arithFails = capRows.filter(r =&gt; Math.abs(r.occ + r.unocc - r.cap) &gt; 0.5)
  checks.push({
    name: "Internal arithmetic: occupied + unoccupied = actual capacity",
    pass: arithFails.length === 0,
    detail: arithFails.length &gt; 0
      ? arithFails.map(r =&gt; `${r.key}: ${r.occ}+${r.unocc}≠${r.cap}`).join("; ")
      : null
  })

  return checks
}

allPass = validationChecks.every(c =&gt; c.pass)

// ── Validation banner ─────────────────────────────────────────────────────
validationBanner = {
  const CITY_CENSUS_URL = "https://www.toronto.ca/city-government/data-research-maps/research-reports/housing-and-homelessness-research-and-reports/shelter-census/"

  if (!allPass) {
    const failedChecks = validationChecks.filter(c =&gt; !c.pass)
    return html`&lt;div style="
      background:#fff3cd;border:1px solid #e0a800;border-radius:4px;
      padding:8px 14px;font-size:0.88em;color:#533f03;margin-bottom:12px"&gt;
      &lt;strong&gt;⚠ Validation issue detected for ${fmtDate(latestDate)}&lt;/strong&gt;
      &lt;details style="margin-top:6px"&gt;
        &lt;summary style="cursor:pointer"&gt;Show details&lt;/summary&gt;
        &lt;ul style="margin:6px 0 0;padding-left:20px"&gt;
          ${failedChecks.map(c =&gt; html`&lt;li&gt;${c.name}${c.detail ? html` — &lt;em&gt;${c.detail}&lt;/em&gt;` : ""}&lt;/li&gt;`)}
        &lt;/ul&gt;
      &lt;/details&gt;
    &lt;/div&gt;`
  }
  if (cityValidation === null) {
    return html`&lt;div style="
      background:#e9ecef;border:1px solid #adb5bd;border-radius:4px;
      padding:8px 14px;font-size:0.88em;color:#495057;margin-bottom:12px"&gt;
      Validation status unavailable in local development
    &lt;/div&gt;`
  }
  if (!cityValidation.city_reachable) {
    return html`&lt;div style="
      background:#fff3cd;border:1px solid #e0a800;border-radius:4px;
      padding:8px 14px;font-size:0.88em;color:#533f03;margin-bottom:12px"&gt;
      ⚠ City of Toronto shelter census page could not be reached · &lt;a href="${CITY_CENSUS_URL}" target="_blank"&gt;View City data →&lt;/a&gt;
    &lt;/div&gt;`
  }
  if (cityValidation.passed && cityValidation.city_date === cityValidation.bonquery_latest_date) {
    return html`&lt;div style="
      background:#d4edda;border:1px solid #76b88d;border-radius:4px;
      padding:8px 14px;font-size:0.88em;color:#1a4731;margin-bottom:12px"&gt;
      ✓ Validated against &lt;a href="${CITY_CENSUS_URL}" target="_blank"&gt;City's Daily Shelter &amp; Overnight Service Usage page&lt;/a&gt; for ${fmtDate(cityValidation.city_date)}
    &lt;/div&gt;`
  }
  if (cityValidation.passed && cityValidation.city_date !== cityValidation.bonquery_latest_date) {
    return html`&lt;div style="
      background:#d4edda;border:1px solid #76b88d;border-radius:4px;
      padding:8px 14px;font-size:0.88em;color:#1a4731;margin-bottom:12px"&gt;
      ✓ Last validated against &lt;a href="${CITY_CENSUS_URL}" target="_blank"&gt;City's Daily Shelter &amp; Overnight Service Usage page&lt;/a&gt; for ${fmtDate(cityValidation.city_date)} · BonQuery data current to ${fmtDate(cityValidation.bonquery_latest_date)} — City page not yet updated
    &lt;/div&gt;`
  }
  return html`&lt;div style="
    background:#fff3cd;border:1px solid #e0a800;border-radius:4px;
    padding:8px 14px;font-size:0.88em;color:#533f03;margin-bottom:12px"&gt;
    ⚠ Discrepancy found for ${fmtDate(cityValidation.city_date)} — BonQuery values differ from &lt;a href="${CITY_CENSUS_URL}" target="_blank"&gt;City's published table&lt;/a&gt;
  &lt;/div&gt;`
}





































viewof selectedDate = Inputs.select(allDates, {
  label: "Date",
  format: d =&gt; fmtDate(d)
})







dayRows = daily_occ.filter(r =&gt; r.date === selectedDate)

function n(v) { return v !== null && v !== undefined ? v.toLocaleString() : "—" }
function pct(v) { return v !== null && v !== undefined ? v.toFixed(1) + "%" : "—" }

function tableRow(r, col1Label) {
  const pad = (r.indent ?? 0) * 16
  const bold = r.is_total ? "font-weight:600" : ""
  const bg   = r.is_total ? "#e8edf5" : "#ffffff"
  if (r.col_type === "summary") {
    return `&lt;tr style="background:${bg}"&gt;
      &lt;td style="padding:5px 10px 5px ${pad}px;${bold}"&gt;${r.label}&lt;/td&gt;
      &lt;td style="padding:5px 10px;text-align:right;${bold}"&gt;${n(r.ind)}&lt;/td&gt;
      &lt;td&gt;&lt;/td&gt;&lt;td&gt;&lt;/td&gt;&lt;td&gt;&lt;/td&gt;&lt;td&gt;&lt;/td&gt;
    &lt;/tr&gt;`
  }
  return `&lt;tr style="background:${bg}"&gt;
    &lt;td style="padding:5px 10px 5px ${pad}px;${bold}"&gt;${r.label}&lt;/td&gt;
    &lt;td style="padding:5px 10px;text-align:right;${bold}"&gt;${n(r.ind)}&lt;/td&gt;
    &lt;td style="padding:5px 10px;text-align:right"&gt;${n(r.occ)}&lt;/td&gt;
    &lt;td style="padding:5px 10px;text-align:right"&gt;${n(r.unocc)}&lt;/td&gt;
    &lt;td style="padding:5px 10px;text-align:right"&gt;${n(r.cap)}&lt;/td&gt;
    &lt;td style="padding:5px 10px;text-align:right"&gt;${pct(r.rate)}&lt;/td&gt;
  &lt;/tr&gt;`
}

function sectionHeader(label, col1, col2, col3) {
  return `&lt;tr style="background:#1a3c6b;color:white;font-weight:600;font-size:0.85em"&gt;
    &lt;td style="padding:7px 10px"&gt;${label}&lt;/td&gt;
    &lt;td style="padding:7px 10px;text-align:right"&gt;Individuals&lt;/td&gt;
    &lt;td style="padding:7px 10px;text-align:right"&gt;${col1}&lt;/td&gt;
    &lt;td style="padding:7px 10px;text-align:right"&gt;${col2}&lt;/td&gt;
    &lt;td style="padding:7px 10px;text-align:right"&gt;${col3}&lt;/td&gt;
    &lt;td style="padding:7px 10px;text-align:right"&gt;Occupancy Rate&lt;/td&gt;
  &lt;/tr&gt;`
}

function summaryHeader() {
  return `&lt;tr style="background:#1a3c6b;color:white;font-weight:600;font-size:0.85em"&gt;
    &lt;td style="padding:7px 10px"&gt;Occupancy Summary&lt;/td&gt;
    &lt;td style="padding:7px 10px;text-align:right"&gt;Individuals&lt;/td&gt;
    &lt;td colspan="4"&gt;&lt;/td&gt;
  &lt;/tr&gt;`
}

dailyTable = {
  const s = (key) =&gt; dayRows.find(r =&gt; r.key === key)

  const allShelterInd = s("all_shelter") ? s("all_shelter").ind : null
  const totalAccomRow = `&lt;tr style="background:#e8edf5;font-weight:600"&gt;
    &lt;td style="padding:5px 10px"&gt;Total People Accommodated †&lt;/td&gt;
    &lt;td style="padding:5px 10px;text-align:right"&gt;${n(allShelterInd)}&lt;/td&gt;
    &lt;td&gt;&lt;/td&gt;&lt;td&gt;&lt;/td&gt;&lt;td&gt;&lt;/td&gt;&lt;td&gt;&lt;/td&gt;
  &lt;/tr&gt;`
  const bridgingRow = `&lt;tr style="background:#f5f5f5;color:#999;font-style:italic"&gt;
    &lt;td style="padding:5px 10px 5px 26px"&gt;Bridging &amp; Triage Programs&lt;/td&gt;
    &lt;td style="padding:5px 10px;text-align:right;font-size:0.85em"&gt;Not published to open data&lt;/td&gt;
    &lt;td&gt;&lt;/td&gt;&lt;td&gt;&lt;/td&gt;&lt;td&gt;&lt;/td&gt;&lt;td&gt;&lt;/td&gt;
  &lt;/tr&gt;`

  const summaryKeys = ["all_shelter","room_based","singles_sector","singles_shelter","allied_summ","temp_summ","iso_summ"]
  const roomKeys    = ["fam_total","fam_emerg","fam_trans_r","fam_hotel","sng_hotel"]
  const bedKeys     = ["singles_total","emerg_total","mix_emerg","men_emerg","wom_emerg","yth_emerg",
                       "trans_total","mix_trans","fam_trans_b","men_trans","wom_trans","yth_trans"]
  const alliedKeys  = ["allied_total","respites","dropin"]

  return html`
    &lt;div style="overflow-x:auto;margin:0 0 1rem"&gt;
    &lt;table style="border-collapse:collapse;width:100%;font-size:0.88em;font-family:'Segoe UI',Arial,sans-serif;min-width:620px"&gt;
      ${summaryHeader()}
      ${totalAccomRow}
      ${bridgingRow}
      ${summaryKeys.map(k =&gt; s(k) ? tableRow(s(k)) : "").join("")}

      ${sectionHeader("Shelter Programs, Room-Based", "Occupied Rooms", "Unoccupied Rooms", "Actual Room Capacity")}
      ${roomKeys.map(k =&gt; s(k) ? tableRow(s(k)) : "").join("")}

      ${sectionHeader("Shelter Programs, Bed-Based", "Occupied Beds", "Unoccupied Beds", "Actual Bed Capacity")}
      ${bedKeys.map(k =&gt; s(k) ? tableRow(s(k)) : "").join("")}

      ${sectionHeader("Allied Services", "Occupied Spaces", "Unoccupied Spaces", "Actual Space Capacity")}
      ${alliedKeys.map(k =&gt; s(k) ? tableRow(s(k)) : "").join("")}

      &lt;tr style="background:#1a3c6b;color:white;font-weight:600;font-size:0.85em"&gt;
        &lt;td style="padding:7px 10px"&gt;Temporary Programs, Bed/Space-Based&lt;/td&gt;
        &lt;td style="padding:7px 10px;text-align:right"&gt;Individuals&lt;/td&gt;
        &lt;td style="padding:7px 10px;text-align:right"&gt;Occupied Beds/Spaces&lt;/td&gt;
        &lt;td style="padding:7px 10px;text-align:right"&gt;Unoccupied&lt;/td&gt;
        &lt;td style="padding:7px 10px;text-align:right"&gt;Actual Capacity&lt;/td&gt;
        &lt;td style="padding:7px 10px;text-align:right"&gt;Occupancy Rate&lt;/td&gt;
      &lt;/tr&gt;
      ${s("temp_resp") ? tableRow(s("temp_resp")) : ""}

      ${sectionHeader("Temporary Programs, Room/Unit-Based", "Occupied Rooms", "Unoccupied Rooms", "Actual Room Capacity")}
      ${s("hotels") ? tableRow(s("hotels")) : ""}

      ${sectionHeader("Temporary Isolation/Recovery Programs", "Occupied Rooms", "Unoccupied Rooms", "Actual Room Capacity")}
      ${s("iso") ? tableRow(s("iso")) : ""}
    &lt;/table&gt;
    &lt;p style="font-size:0.8em;color:#666;margin:4px 0 0"&gt;
      † Total People Accommodated excludes Bridging &amp; Triage programs,
      which are tracked in the City's operational system but not published
      to open data.
    &lt;/p&gt;
    &lt;/div&gt;`
}


















































This table reproduces the City of Toronto’s Daily Shelter & Overnight Service Usage report using the City’s open data. Two known differences from the City’s live dashboard: it does not include Bridging & Triage programs, which are not published to open data (29 people on May 14, 2026); and for emergency programs, “Actual Bed Capacity” counts beds currently available for use and excludes beds temporarily offline, which the City’s live dashboard includes. Occupancy and individual counts match the City’s figures exactly. A full side-by-side comparison is available on the data validation page.
