    ticks: spanMonths &lt;= 3 ? d3.utcDay.every(7) : spanMonths &lt;= 18 ? d3.utcMonth.every(1) : 8,
    tickFormat: d =&gt; {
      const m = d.getMonth(), y = d.getFullYear()
      if (spanMonths &lt;= 18) return m === 0 ? `${MON[m]}-${y}` : MON[m]
      return m === 0 ? String(y) : m === 6 ? `Jul ${y}` : ""
    }
  }
})()

