      `Returned to Shelter:    +${d.returned_to_shelter.toLocaleString()}`,
      `Became Inactive:        −${d.became_inactive.toLocaleString()}`,
      `Moved to Housing:       −${d.moved_to_housing.toLocaleString()}`
    ].join("\n")
  }
})

